[AvaloniaFact]
public async Task ClaudeMissingKey_HasNoComboBox()
{
    // ── arrange: Settings with only HF_TOKEN (no ANTHROPIC_API_KEY) ──
    var env = new DictionaryEnvironmentAccessor
    {
        ["HF_TOKEN"] = "hf-dummy",
    };
    var repo = new TestRepository();
    SettingsTestHelpers.WriteCommitConfig(repo, commitProofArtifacts: false);
    using var _ = SettingsTestHelpers.SeedUserEnv(env, repo, "");
    var vm = new MainWindowViewModel(repo, env);
    var window = new MainWindow { DataContext = vm };
    window.Show();
    Dispatcher.UIThread.RunJobs();

    var settings = SettingsTestHelpers.OpenSettings(window);
    try
    {
        var settingsRoot = settings.GetVisualRoot();
        Assert.NotNull(settingsRoot);

        var litTierItems = settingsRoot.FindControl<ItemsControl>("LitTierItems");
        Assert.NotNull(litTierItems);

        // ── act: count ComboBox descendants vs editable rows ──
        var comboBoxes = litTierItems
            .GetVisualDescendants()
            .OfType<ComboBox>()
            .ToList();

        // Gather each row's DataContext (TierModelRow) via the
        // ItemsControl items so we count only rows that are editable.
        var editableCount = 0;
        for (var i = 0; i < litTierItems.ItemCount; i++)
        {
            var container = litTierItems.ContainerFromIndex(i);
            if (container?.DataContext is MainWindowViewModel.TierModelRow row
                && row.IsEditable)
            {
                editableCount++;
            }
        }

        // ── assert: only editable rows get a ComboBox ──
        Assert.Equal(editableCount, comboBoxes.Count);
    }
    finally
    {
        settings.Close();
    }
}

